insert  into `benchmark`(`id`,`program_id`,`jeniskegiatan_id`,`kegiatan_id`,`desa_id`,`kecamatan_id`,`kabupaten_id`,`provinsi_id`,`tanggalimplementasi`,`handler`,`usercompiler_id`,`score`,`catatanevaluasi`,`area`,`created_at`,`updated_at`) values (1,1,1,2,5104031003,510403,5104,51,'2025-05-31','e',1,'1.00','e',NULL,'2025-05-31 21:15:32','2025-05-31 21:15:39'),(2,1,1,2,5104031003,510403,5104,51,'2025-06-02','hgf',1,'76.00','nbv','jb','2025-06-02 10:50:44','2025-06-02 10:50:44'),(3,1,1,2,5104031003,510403,5104,51,'2025-06-02','ruris',1,'50.00','aman aja','aman aja','2025-06-02 11:55:04','2025-06-02 11:55:04'),(4,8,3,12,9103162003,910316,9103,91,'2025-06-20','Uciha Obito',1,'87.00','Penguatan Penguatan Penguatan Penguatan Penguatan','The report describes aspects of the current state of biodiversity, ecology, sustainable agriculture, local socio-cultural practices, and the sustainable economy in Kapuas Hulu, including the level of awareness among the community regarding those aspects. Moreover, the results also emphasize the need for improvements in community knowledge, attitudes, and practical implementation. Please read the full report here.','2025-06-20 00:52:41','2025-06-20 00:52:41'),(5,8,3,12,9103162003,910316,9103,91,'2025-05-01','Narutooo',3,'77.00','The report describes aspects of the current state of biodiversity, ecology, sustainable agriculture, local socio-cultural practices, and the sustainable economy in Kapuas Hulu, including the level of awareness among the community regarding those aspects. Moreover, the results also emphasize the need for improvements in community knowledge, attitudes, and practical implementation. Please read the full report here.','Using both qualitative and quantitative study methods, the assessment focused on collecting data related to biodiversity, soil health, water conservation, carbon sequestration, and climate change mitigation and adaptation. It identifies areas for improvement in the agricultural systems and proposes strategies to enhance sustainability, environmental management, and community livelihoods based on the existing potential in each location.','2025-06-20 00:54:08','2025-06-20 00:54:08'),(6,9,1,13,5103032008,510303,5103,51,'2025-06-20','Kadek',1,'90.00','Lorem ipsum dolor sit amet, consectetur adipiscing elit.','Lorem ipsum dolor sit amet, consectetur adipiscing elit.','2025-06-20 18:27:06','2025-06-20 18:27:06'),(7,14,3,16,1105072002,110507,1105,11,'2025-06-30','t',1,'5.00','tt','tt','2025-06-30 20:22:18','2025-06-30 20:26:39');

