insert  into `trkegiatankampanye`(`id`,`kegiatan_id`,`kampanyeyangdikampanyekan`,`kampanyejenis`,`kampanyebentukkegiatan`,`kampanyeyangterlibat`,`kampanyeyangdisasar`,`kampanyejangkauan`,`kampanyerencana`,`kampanyekendala`,`kampanyeisu`,`kampanyepembelajaran`,`created_at`,`updated_at`) values (1,7,'<p>Kampanye air</p>','<p>Memasang poster di kantor kementerian</p>','<p>Menteri LH</p>','<p>Staff kementerian</p>','<p>100 Orang</p>','<p>Lanjut ke kementerian lainnya</p>','<p>Kendala/Tantangan Dan Solusi Yang Diterapkan </p><p>Kendala/Tantangan Dan Solusi Yang Diterapkan </p><p>Kendala/Tantangan Dan Solusi Yang Diterapkan </p><p>Kendala/Tantangan Dan Solusi Yang Diterapkan </p><p>Kendala/Tantangan Dan Solusi Yang Diterapkan </p><p>Kendala/Tantangan Dan Solusi Yang Diterapkan </p><p>Kendala/Tantangan Dan Solusi Yang Diterapkan </p><p><br></p>','<p>Isu Yang Perlu Dipehatikan Dan Rekomendasinya </p><p>Isu Yang Perlu Dipehatikan Dan Rekomendasinya </p><p>Isu Yang Perlu Dipehatikan Dan Rekomendasinya </p><p>Isu Yang Perlu Dipehatikan Dan Rekomendasinya </p><p><br></p>','<p>Bawa posternya lebih banyak</p>','<p>Dukungan publik</p>','2025-06-19 13:34:07','2025-12-27 16:58:19');

/*Data for the table `trkegiatankonsultasi` */

insert  into `trkegiatankonsultasi`(`id`,`kegiatan_id`,`konsultasilembaga`,`konsultasikomponen`,`konsultasiyangdilakukan`,`konsultasihasil`,`konsultasipotensipendapatan`,`konsultasirencana`,`konsultasikendala`,`konsultasiisu`,`konsultasipembelajaran`,`created_at`,`updated_at`) values (3,5,'<p>Ketiga program ini menjadi manifestasi nyata dari visi Diktisaintek Berdampak, yaitu pendidikan tinggi harus hadir sebagai solusi bagi rakyat. Kemdiktisaintek berkomitmen mengawal riset dan pengabdian agar menjadi lokomotif perubahan sosial, ekonomi, dan ekosistem inovasi nasional.</p><p><br></p>','<p>Sebagaimana Menteri Brian mengajak, “Mari kita manfaatkan program-program penelitian dan pengabdian kepada masyarakat ini sebagai arah kebijakan yang memperkuat kontribusi ilmu pengetahuan dan teknologi bagi kemajuan bangsa.”</p><p><br></p>','<p>Sementara itu, semangat kolaborasi dan pemberdayaan juga digaungkan melalui Program Mahasiswa Berdampak yang secara khusus menggerakkan potensi kepemimpinan dan empati sosial mahasiswa sebagai aktor pengubah di tengah masyarakat. Program Mahasiswa Berdampak: Pemberdayaan Masyarakat oleh BEM merupakan terobosan Kemdiktisaintek yang memperkuat posisi mahasiswa sebagai pelaku utama pembangunan sosial. Melalui kepemimpinan kolektif Badan Eksekutif Mahasiswa (BEM), program ini memberikan ruang strategis bagi generasi muda untuk berkontribusi langsung pada pemecahan persoalan-persoalan riil di masyarakat.</p><p><br></p>','<p>Kosabangsa 2025 akan menargetkan daerah tertinggal, wilayah rawan bencana, dan kawasan kemiskinan ekstrem. Fokus intervensi mencakup pengembangan ekonomi lokal, sistem pertanian berkelanjutan, kesehatan masyarakat berbasis komunitas, pendidikan adaptif, hingga pemanfaatan teknologi tepat guna. Lebih dari sekadar program pengabdian, Kosabangsa adalah medium rekayasa sosial berbasis iptek untuk memperkuat ketahanan masyarakat akar rumput dan mendorong transformasi sosial dari bawah. Mahasiswa, dosen, dan masyarakat menjadi bagian dari ekosistem perubahan yang saling belajar, tumbuh, dan mandiri bersama.</p><p><br></p>','<p>“Kita tidak hanya ingin menghasilkan penelitian dan aktivitas pengabdian. Kita ingin melihat perubahan di desa, transformasi di sektor strategis, kemandirian komunitas, akses teknologi yang terbuka, dan produk riset yang bisa dikomersialisasi serta memberi nilai tambah bagi masyarakat,” ungkap Dirjen Fauzan.</p><p><br></p>','<p>Mendiktisaintek menegaskan bahwa tridarma perguruan tinggi tidak hanya menjadi wujud dari komitmen akademik, tetapi juga sebagai motor penggerak perubahan, perbaikan, dan kemajuan peradaban bangsa Indonesia.</p><p><br></p>','<p>Dalam sambutannya, Menteri Pendidikan Tinggi, Sains, dan Teknologi (Mendiktisaintek), Brian Yuliarto, menyatakan bahwa program-program ini menjadi instrumen strategis untuk mengarahkan riset dan pengabdian agar semakin relevan dan berdampak terhadap kebutuhan bangsa.</p><p><br></p>','<p>Ketiga program tersebut adalah Program Mahasiswa Berdampak: Pemberdayaan Masyarakat oleh BEM, Program Peningkatan Ekosistem Riset dan Inovasi PUI-PT, serta Call for Proposal Program Kosabangsa Tahun 2025. Acara peluncuran ini diselenggarakan secara daring melalui kanal YouTube Kemdiktisaintek pada Rabu (14/5).</p><p><br></p>','<p>Program yang berdampak pada murid yaitu rancangan atau perencanaan satu unit atau kesatuan kegiatan yang berkesinambungan dalam proses pembelajaran, yang memiliki tujuan, dan melibatkan sekelompok orang (guru dan murid) untuk mencapai tujuan yang telah ditetapkan, sehingga memberikan pengalaman bermakna bagai murid dan memberikan bekal untuk mereka menjadi pembelajar sepanjang hayat.</p><p><br></p>','2025-05-23 16:38:06','2025-05-23 16:38:06');

