insert  into `trmeals_penerima_manfaat`(`id`,`program_id`,`user_id`,`dusun_id`,`nama`,`no_telp`,`jenis_kelamin`,`rt`,`rw`,`umur`,`is_head_family`,`head_family_name`,`keterangan`,`is_non_activity`,`created_at`,`updated_at`,`deleted_at`) values (1,1,2,5,'I Gusti Komang Rauh Subagia','085920512588','laki','001','001',11,1,'I Gusti Komang Rauh Subagia','gusti.subagia@kapitmas.com\nCasting\nRubber Mold',0,'2025-04-04 18:53:56','2025-09-07 23:39:57',NULL),(2,1,1,5,'Ni Made Adi Sariyati','08191199293','laki','323','111',23,1,'Ni Made Adi Sariyati','1.\nTahun Mulai : 2002\nTahun Akhir : 2008\nRiwayat : SDN 1 Kerobokan Kaja\n2.\nTahun Mulai : 2008\nTahun Akhir : 2011\nRiwayat : SMP Ngurah Rai\n3.\nTahun Mulai : 2011\nTahun Akhir : 2014\nRiwayat : SMK Wira Harapan\n4.\nTahun Mulai : 2014\nTahun Akhir : 2018\nRiwayat : STIKI Indonesia',0,'2025-04-12 05:18:10','2025-05-13 12:12:51',NULL),(3,1,1,5,'Lely Meilina','08232323222','perempuan','222','221',13,1,'Lely Meilina','Tahun Mulai : 2013\nTahun Akhir : 2020\nRiwayat : CV. Code Artisan\nJabatan / Posisi : Programmer Freelance\n\nTahun Mulai : 2015\nTahun Akhir : 2018\nRiwayat : PT. Adi Citra Sakti\nJabatan / Posisi : IT Support\n\nTahun Mulai : 2018\nTahun Akhir : 2020\nRiwayat : Dinas Komunikasi dan Informatika Kabupaten Badung\nJabatan / Posisi : Programmer',1,'2025-04-12 05:19:42','2025-05-13 12:13:05',NULL),(4,1,2,8,'rur','081234556789000','perempuan','005','001',80,0,NULL,'anu anu anu',1,'2025-04-24 18:44:00','2025-04-24 18:45:37','2025-04-24 18:45:37'),(5,1,1,3,'Zinedine Zidane',NULL,'laki','xxx','xxx',52,1,'Zinedine Zidane','Zinedine Yazid Zidane, popularly known as Zizou, is a French professional football manager and former player who played as an attacking midfielder. He most recently coached La Liga club Real Madrid and is one of the most successful coaches in the world. Widely regarded as one of the greatest players of all time, Zidane was a playmaker renowned for his elegance, vision, passing, and ball control. He received many individual accolades as a player, including being named FIFA World Player of the Year in 1998, 2000 and 2003, and winning the 1998 Ballon d&amp;amp;amp;#039;Or.',1,'2025-05-01 18:32:55','2025-05-13 12:33:39',NULL),(6,4,2,9,'Zinedine Zidane Jr','081999333222','laki','123','123',54,1,'Zinedine Zidane Jr','French footballer and coach',1,'2025-05-05 13:29:54','2025-05-13 12:35:03',NULL),(7,5,2,10,'David Beckham','0833366111','laki','-','-',54,1,'David Beckham','Beckham&#039;s professional club career began with Manchester United, where he made his first-team debut in 1992 at age 17.\n\nWith United, he won the Premier League title six times, the FA Cup twice, the FA Charity Shield twice, the Intercontinental Cup and the UEFA Champions League in 1999\n\n\nClub career\nManchester United\n1991–1994: Youth and early-career\nHaving signed for Manchester United as a trainee on 8 July 1991,[45] Beckham was part of a group of young players, including Ryan Giggs, Gary Neville, Phil Neville, Nicky Butt and Paul Scholes, who were coached by Eric Harrison, and helped the club win the FA Youth Cup in May 1992. Beckham scored Manchester United&#039;s second goal in the 30th minute of their 3–1 first-leg win of the final against Crystal Palace on 14 April 1992. In the second leg on 15 May, Beckham played a full 90-minutes of the fixture which ended 3–2 in favour of Manchester United and 6–3 on aggregate. Beckham&#039;s impact led to a first-team debut on 23 September 1992, as a substitute for Andrei Kanchelskis in a League Cup match against Brighton &amp; Hove Albion. Shortly afterwards, Beckham signed as a professional on 23 January 1993',1,'2025-05-05 13:34:40','2025-05-13 12:34:05',NULL),(8,5,2,10,'Victoria Beckham',NULL,'perempuan','000','000',51,0,'David Beckham','Victoria Caroline Beckham (née Adams; born 17 April 1974)[1][2] is an English fashion designer, singer, and television personality. She rose to prominence in the 1990s as a member of the pop group the Spice Girls, in which she was nicknamed Posh Spice. With over 100 million records sold worldwide,[3] the group became the best-selling female group of all time.[4][5] After the Spice Girls disbanded in 2001, Beckham signed with Virgin Records, to release her self-titled debut solo album, which produced two UK Top 10 singles. Beckham has also become an internationally recognised style icon and fashion designer.',1,'2025-05-05 13:36:21','2025-05-05 13:36:21',NULL),(9,5,2,5,'Yu Ji-min',NULL,'perempuan','000','000',25,0,'David Beckham','Yu Ji-min (Korean: 유지민; born April 11, 2000), known professionally as Karina, is a South Korean singer and rapper. She is the leader of the South Korean girl group Aespa, formed by SM Entertainment on November 17, 2020. She is also a member of the supergroup Got the Beat, which debuted on January 3, 2022.',1,'2025-05-05 13:38:18','2025-05-13 12:56:04',NULL),(10,7,2,5,'Alisson Becker',NULL,'laki','111','111',32,1,'Alisson Becker','https://www.premierleague.com/players/20559/Alisson-Becker/overview',0,'2025-05-13 12:48:48','2025-05-13 12:48:48',NULL),(11,7,2,9,'Ollie Watkins',NULL,'laki','-','-',26,1,'Ollie Watkins','Ollie Watkins became Aston Villa\'s all-time leading Premier League goalscorer as they boosted their UEFA Champions League hopes with a 1-0 win at AFC Bournemouth, whose own European ambitions suffered a setback',0,'2025-05-13 12:48:48','2025-05-13 12:48:48',NULL),(12,7,2,5,'Alexander Isak',NULL,'laki','000','000',25,1,'Alexander Isak','Alexander Isak\n21/09/1999 (25)\n\nAlexander Isak (born 21 September 1999) is a Swedish professional footballer who plays as a striker for Premier League club Newcastle United and the Sweden national team. \n\nhttps://www.premierleague.com/players/21737/Alexander-Isak/overview',1,'2025-05-13 12:52:21','2025-05-13 12:52:21',NULL),(13,7,2,10,'Matz Sels',NULL,'laki','111','111',32,0,'Nottingham Forest','Matz Willy Els Sels (born 26 February 1992) is a Belgian professional footballer who plays as a goalkeeper for Premier League club Nottingham Forest and the Belgium national team.',0,'2025-05-13 12:54:44','2025-05-13 12:54:44',NULL),(14,2,2,9,'Obito Uchiha','0893332221','laki','000','000',55,0,'Minato Namikaze','Obito grew up not knowing who his parents were; in the anime, he was left in the care of his grandmother.[7] Feeling alone in the world, Obito dreamed of becoming Hokage so that the people of the village would acknowledge his existence.[8] He enrolled in the Academy to help him achieve that goal, where he developed a one-sided rivalry with Kakashi, whose natural talent and popularity he was jealous of. He also became a close friend of Rin Nohara, whom he eventually fell in love with. After finally graduating some years later, Obito, Rin, and Kakashi were placed on a team under the leadership of Minato',0,'2025-05-22 15:54:32','2025-05-22 16:15:42',NULL),(15,2,2,11,'Agueroo','081333993312','laki','000','000',22,1,'Agueroo','Dusun Sahunlatter',1,'2025-05-22 15:54:32','2025-05-22 15:54:32',NULL),(16,2,2,12,'Sasuke Uchiha','081999332','laki','002','001',28,1,'Sasuke Uchiha','Sasuke Uchiha (うちはサスケ, Uchiha Sasuke) is one of the last surviving members of Konohagakure&#039;s Uchiha clan. After his older brother, Itachi, slaughtered their clan, Sasuke made it his mission in life to avenge them by killing Itachi. He is added to Team 7 upon becoming a Shinobi, and, through competition with his rival and best friend, Naruto Uzumaki, Sasuke starts developing his skills but eventually grows dissatisfied with his progress. He defects from Konoha so that he can acquire the strength needed to exact his revenge and master the Cursed Seal of Heaven. His years of seeking vengeance and the actions that followed became increasingly demanding, irrational, and isolated from others, leading him to be branded as an international criminal. After learning the truth of his brother&#039;s sacrifice, later proving instrumental in ending the Fourth Shinobi World War, and being happily redeemed by Naruto, Sasuke decides to return to Konoha and dedicate his life to help protect the village and its inhabitants, becoming referred to as the &quot;Supporting Kage&quot; (支う影, Sasaukage, literally meaning: Supporting Shadow).',0,'2025-05-22 15:58:56','2025-05-22 15:58:56',NULL),(17,2,2,13,'Kakashi Hatake','0819993322','laki','001','001',45,1,'Kakashi Hatake','In the anime, Kakashi and Tsunade tried to stop the Konoha Military Police Force from exposing the identities of everyone connected to Root in the aftermath of the group disbanding, in order to avoid suspicion among villagers thinking each other were former members. However, many names were still revealed, causing those people to become ostracised',1,'2025-05-22 16:15:21','2025-05-22 16:15:21',NULL),(18,2,2,14,'Minato Namikaze',NULL,'laki','000','000',33,1,'Minato Namikaze','Minato Namikaze (波風ミナト, Namikaze Minato) was the Fourth Hokage (四代目火影, Yondaime Hokage, literally meaning: Fourth Fire Shadow) of Konohagakure. He was renowned all over the world as Konoha&#039;s Yellow Flash (木ノ葉の黄色い閃光, Konoha no Kiiroi Senkō, English TV: Yellow Flash of the Leaf). He died during the Nine-Tailed Demon Fox&#039;s Attack, sacrificing his life to seal a half of the Nine-Tails into himself and the other half into his newborn son, Naruto Uzumaki.',1,'2025-05-22 16:18:15','2025-05-22 16:18:15',NULL),(19,1,2,15,'test',NULL,'laki','010','010',35,1,'test','test',0,'2025-05-30 12:17:06','2025-05-30 12:17:06',NULL),(20,2,2,15,'nikimoto situmorang','08214444444','laki','010','010',18,0,'-',NULL,0,'2025-05-30 12:31:12','2025-05-30 12:31:12',NULL),(21,2,2,15,'rur',NULL,'laki','011','011',19,0,'-',NULL,0,'2025-05-30 12:33:48','2025-05-30 12:33:48',NULL),(22,8,1,16,'I WAYAN MADE','088824324','laki','00','00',88,1,'I WAYAN MADE','Lorem ipsum dolor sit amet, consectetur adipiscing elit. Sed do eiusmod tempor incididunt ut labore et dolore magna aliqua. Ut enim ad minim veniam, quis nostrud exercitation ullamco laboris nisi ut aliquip ex ea commodo consequat. Duis aute irure dolor in reprehenderit in voluptate velit esse cillum dolore eu fugiat nulla pariatur. Excepteur sint occaecat cupidatat non proident, sunt in culpa qui officia deserunt mollit anim id est laborum.',0,'2025-06-19 23:37:41','2026-01-02 00:56:29',NULL),(23,9,1,16,'I wayan','08111111','laki','00','00',45,1,'I wayan','Lorem ipsum dolor sit amet, consectetur adipiscing elit.',1,'2025-06-20 18:24:21','2025-06-20 18:24:21',NULL),(24,14,1,16,'Kepala 1','099999','laki','00','00',88,1,'Kepala 1','test',0,'2025-06-30 20:17:20','2025-06-30 20:17:20',NULL),(25,14,1,16,'Ryan','09999','lainnya','00','00',32,0,'Kepala 1','test',0,'2025-06-30 20:17:21','2026-01-28 02:30:49',NULL),(26,7,1,18,'Kim Ji Won','081337353585','perempuan','xxx','xxx',31,1,'Kim Ji Won','Kim Ji Won\nDusun Korea\nProgam XX',0,'2026-01-01 23:21:35','2026-01-01 23:21:35',NULL),(27,7,1,19,'Ronaldinho','081337353585','laki','222','111',42,1,'Ronaldinho','Ronaldinho',0,'2026-01-01 23:21:35','2026-01-01 23:21:35',NULL),(28,7,1,9,'Mr. Beast','082144570010','laki','2223','332',23,1,'Mr. Beast','Mr. Beast',0,'2026-01-01 23:46:57','2026-01-01 23:46:57',NULL),(29,8,1,9,'Linus Sebastian','081337353585','laki','000','000',34,1,'Linus Sebastian','Tambah Peserta Yang Terlibat\n Tambah Peserta Yang Terlibat\n Tambah Peserta Yang Terlibat\n Tambah Peserta Yang Terlibat\n Tambah Peserta Yang Terlibat',0,'2026-01-02 01:23:49','2026-01-02 01:23:49',NULL),(30,14,1,5,'Cristiano Ronaldo','081337353585','lainnya','-','-',34,1,'Cristiano Ronaldo','Informasi ProgramInformasi ProgramInformasi ProgramInformasi ProgramInformasi ProgramInformasi Program',0,'2026-01-28 02:01:50','2026-01-28 02:01:50',NULL);

