insert  into `trprogramgoal`(`id`,`program_id`,`deskripsi`,`indikator`,`target`,`created_at`,`updated_at`) values (1,2,'Deskripsi Goals Program','Indikator Goals Program','Target Goals Program','2024-11-15 11:20:04','2024-11-15 11:20:04'),(2,3,'To enhance community resilience by reducing the risk of disaster in disaster-prone areas of Indonesia','Disaster risks and preparedness measures practiced by the communities in disaster-prone areas of Indonesia','- 2 Community Disaster Management Groups (KMPB) established and started to function\r\n- 2 schools in 2 villages started to implement Disaster-safe Education Unit (SPAB)\r\n- Disaster-related risk communication implemented by 2 Community Disaster Management Groups (KMPB) and teachers from 2 schools\r\n- Community in 2 villages started to implement climate-resilience livelihood','2024-11-15 11:34:07','2024-11-15 11:34:07'),(3,4,'Deskripsi','Indikator','Target','2024-12-06 18:20:51','2024-12-06 18:20:51'),(4,5,'Deskripsi','Deskripsi','Deskripsi','2024-12-06 18:44:10','2024-12-06 18:44:10'),(5,8,'Program X Goals','Program X Indikator','Program X Target','2025-06-19 23:16:44','2025-11-10 01:03:23'),(6,9,'Lorem ipsum dolor sit amet, consectetur adipiscing elit.','-Indikator Goals','-Target Goals','2025-06-20 18:14:44','2025-06-20 18:14:44'),(7,14,'Lorem Ipsum is simply dummy text of the printing and typesetting industry.','-Goals Indikator 1\r\n-Goals Indikator 2\r\n-Goals Indikator 3','-Goals Target 1\r\n-Goals Target 2\r\n-Goals Target 3','2025-06-30 19:48:23','2025-06-30 19:48:23'),(8,1,'Program Goals Deskripsi','Program Goals Indikator','Program Target Indikator','2025-08-20 23:24:33','2025-11-09 23:51:46'),(9,15,'MU Juara Liga Inggris\r\n\r\nManchester United selalu saja dipenuhi masalah setiap memulai musim. Meski diarsiteki Erik Ten Hag yang membuat impresi di musim pertamanya dengan MU, tapi Setan Merah tetap belum meyakinkan.','MU Juara Liga Inggris\r\n\r\nManchester United selalu saja dipenuhi masalah setiap mem