insert  into `trprogramobjektif`(`id`,`program_id`,`deskripsi`,`indikator`,`target`,`created_at`,`updated_at`) values (1,2,'To strengthen the development of a community-based food forest for climate justice campaign through the improvement of water access for the community in Banjar Bukit Sari, Sumberklampok Village, North Bali','- # of families improved their access to water through the irrigation system developed\r\n- # of families directly benefited from the food forest components developed\r\n- # of the community members improved their capacity on food forest development\r\n- % of women\'s participation rate in the program\r\n- # of people reached by the climate justice campaign','- 107 families improved\r\n- 30 families benefited\r\n- 30 community members improved\r\n- 35% of women participation rate\r\n- 1,000,000 people reached by the climate justice campaign','2024-11-15 11:20:04','2025-01-17 15:46:22'),(2,3,'To strengthen community-based Disaster Risk Reduction, including Climate Change Adaptation and Mitigation, through capacity development in disaster-prone areas in Indonesia','Capacity of the communities in 2 disaster-prone villages in Indonesia increased on communitiy-based Disaster Risk Reduction, including Climate Change Adaptation and Mitigation','- Capacity of 60 community representatives increased on community-based Disaster Risk Reduction by 85% on average\r\n- 2 Community Disaster Management Groups (KMPB) established and strengthened\r\n- Capacity of 2 schools increased on Disaster-safe Education Unit (SPAB)\r\n- 2 Community Disaster Management Groups (KMPB) and teachers from 2 schools engaged on disaster-related risk communication\r\n- Capacity of 60 community representatives increased on climate-resilience livelihood','2024-11-15 11:34:07','2024-11-15 11:34:07'),(3,4,'Objectif','Indikator','Target','2024-12-06 18:20:51','2024-12-06 18:20:51'),(4,5,'Deskripsi','Indikator','Target','2024-12-06 18:44:10','2024-12-06 18:44:10'),(5,8,'Lorem ipsum do