insert  into `trprogramoutcomeoutputactivity`(`id`,`kode`,`nama`,`programoutcomeoutput_id`,`deskripsi`,`indikator`,`target`,`created_at`,`updated_at`) values (1,'#11.11','ManUtd U-18',1,'ManUtd U-18','ABC','ManUtd U-18','2024-11-05 10:44:05','2025-09-19 03:46:28'),(2,'#11.12','Welcome To Manchester United',1,'The official Manchester United website with news, fixtures, videos, tickets, live match coverage, match highlights, player profiles, transfers, shop and more','Bruno Fernandes and Bryan Mbeumo will play as the free-flowing attacking midfielders for the home team in the opponent’s half. Both of them would have to carry most of the offensive workload for Man United this weekend.','Amad Diallo and Manuel Ugarte will be named on the bench and might come on to influence the game in the second half if required.','2024-11-05 10:44:05','2025-09-19 03:42:06'),(3,'#11.12','nama-#11.12',2,'Deskripsi  Kegiatan #1 dari Output #1 di Outcome #2 dg Program #1','Indikator Kegiatan #1 dari Output #1 di Outcome #2 dg Program #1','Target Kegiatan dari #1  Output #1 di Outcome #2 dg Program #1','2024-11-05 15:17:20','2024-11-05 15:17:20'),(4,'#11.12','nama-#11.12',2,'Deskripsi  Kegiatan #2 dari Output #1 di Outcome #2 dg Program #1','Indikator Kegiatan #2 dari Output #1 di Outcome #2 dg Program #1','Target Kegiatan #2 dari Output #1 di Outcome #2 dg Program #1','2024-11-05 15:17:20','2024-11-05 15:17:20'),(5,'#11.12','nama-#11.12',3,'deskripsi','indikator','target','2024-11-05 19:56:56','2024-11-05 19:56:56'),(6,'2.1.1','Asesmen dan seleksi partisipan',4,'Conduct assessment and selection process for training participants','- # of assessment activities conducted\n- # of training participants selected (35% women)','- 2 activities\n- 30 people (9 women)','2024-11-15 11:23:11','2025-01-17 15:50:34'),(9,'1.1.1','Asesmen',5,'Conduct assessment in targeted villages, including targeted schools and potential climate-resilience livelihood, and beneficiary selection in collaboration with village stakeholders','- # of villages assessed\n- # of schools assessed\n- # of beneficiaries selected, disaggregated by gender and age (at least 30% women, 30% youth)','- 2 villages\n- 2 schools (1 in Jembrana, 1 Lembata)\n- 60 people:\n   *30 in Jembrana, 30 in Lembata\n   *18 women and 18 youth in Jembrana and Lembata','2024-11-15 11:54:32','2025-01-17 14:38:10'),(10,'#kode','#activity-name',8,'Organize program introduction to the communities and stakeholders at village level','# of meetings organized','\"2 meetings \n(1 in Jembrana, 1 in Lembata)\"','2024-11-15 11:54:32','2024-11-15 11:54:32'),(23,'#kode-2','#activity-name',8,'1.1.1','1.1.1','1.1.1','2024-12-06 18:23:14','2024-12-10 18:17:07'),(24,'#kode-3','#activity-name',9,'Deskripsi Kegiatan	1.1.1','Indikator Kegiatan	1.1.1','Target Kegiatan 1.1.1','2024-12-06 18:47:50','2024-12-10 18:16:04'),(25,'#kode-4','#activity-name',9,'Deskripsi Kegiatan	1.1.2','Indikator Kegiatan	1.1.2','Target Kegiatan 1.1.3','2024-12-10 18:16:04','2024-12-10 18:16:04'),(26,NULL,NULL,5,NULL,NULL,NULL,'2025-01-17 14:20:45','2025-01-17 14:20:45'),(27,'2.1.1','Table Top Exercise and disaster drill development',10,'Develop Table Top Exercise and disaster drills scenario for emergency response based on the communities\' disaster risk priority','- # of meetings conducted\n- # of scenario for Table Top Exercise developed\n- # of scenario for disaster drills developed',NULL,'2025-01-17 14:48:38','2025-01-17 14:48:38'),(28,'3.1.1','Asesemen',11,'Conduct assessment to identify potential climate-resilience livelihood, including but not limited climate-smart agriculture and post-harvest production, in targeted villages','# of villages assessed','2 villages (1 in Jembrana, 1 Lembata)','2025-01-17 15:08:32','2025-01-17 15:08:32'),(29,'4.1.1','Workshop pengembangan materi KIE',12,'Conduct 1-day workshop to develop disaster-related IEC materials, including climate adaptation and mitigation, with Community Disaster Management Group (KMPB) and school te